 Begin SpecMap 	# Conversion between spectral coordinate systems
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nspec = 2 	# Number of conversion steps
    Spec1 = "GEF2HL" 	# Convert from Geocentric to heliocentric frequency
    Spec1a = 0.5 	# UT1 epoch of observaton (Modified Julian Date)
    Spec1b = 1.2 	# RA of source (FK5 J2000, radians)
    Spec1c = 51544 	# DEC of source (FK5 J2000, radians)
    Spec2 = "HLF2GE" 	# Convert from Heliocentric to geocentric frequency
    Spec2a = 0.5 	# UT1 epoch of observaton (Modified Julian Date)
    Spec2b = 1.2 	# RA of source (FK5 J2000, radians)
    Spec2c = 51544 	# DEC of source (FK5 J2000, radians)
 End SpecMap
